registerTool(
  "take_auto_align",
  {
    title: "Auto-align a take's onsets to the group's reference lane",
    description: "Onset-based micro-alignment: measure how far a take lane's note/word onsets sit early or late versus the group's FIRST lane (the reference \u2014 the original material; AI-fix lanes from ai_import_clip_fix land in groups built that way), and nudge the take by MINUS that offset so its phrasing locks to the reference. Detects onsets with the same detector clip_detect_transients uses, over the overlap of the two lanes, searches \xB1searchWindowMs, and refines to sub-millisecond precision. Set apply=false for a dry-run measurement (no change, no undo entry). INCONCLUSIVE cases (fewer than 2 matching onsets, or non-overlapping lanes) error instead of guessing \u2014 widen searchWindowMs or use take_move. Aligning lane 0 against itself is rejected (it IS the reference). An apply that would push the take before beat 0 (not enough timeline headroom for the earlier move) errors instead of clamping \u2014 take_move the group later first, then align. Applying is one undo step. Returns the report: `{offsetMs, offsetBeats, matchedOnsets, referenceOnsets, candidateOnsets, confidence, applied}` (positive offsetMs = the take was late).",
    inputSchema: {
      trackId: external_exports.string().min(1).describe("Id of the track that owns the group, from project_snapshot."),
      groupId: external_exports.string().uuid().describe("Id of the take group, from take_group's result or project_snapshot."),
      laneId: external_exports.string().uuid().describe(
        "Id of the lane (take) to align \u2014 e.g. an 'AI Fix N' lane from ai_import_clip_fix. Must not be the group's first (reference) lane."
      ),
      searchWindowMs: external_exports.number().min(10).max(500).optional().describe(
        "\xB1 search window in milliseconds around the take's current position (10..500, default 150). Widen it if alignment comes back inconclusive."
      ),
      apply: external_exports.boolean().optional().describe(
        "true (default) moves the take by the measured offset in one undo step; false only measures and reports."
      )
    }
  },
  async ({ trackId, groupId, laneId, searchWindowMs, apply }) => toToolResult(() => bridge.send("take.autoAlign", { trackId, groupId, laneId, searchWindowMs, apply }))
);
registerTool(
  "groove_extract",
  {
    title: "Extract a groove template from a clip's feel",
    description: "Capture the TIMING FEEL of a clip as a reusable GROOVE (a per-slot offset table) and save it to the project. From a MIDI clip it reads the note onsets; from an AUDIO clip it detects the transients first (same engine as clip_detect_transients). Each onset snaps to its nearest grid slot; the offsets you played (ahead of / behind the grid) are AVERAGED per slot and folded into the cycle, so the result is the characteristic push/lay-back of the take. Slots with no onset read 0 (straight). `gridBeats` (default 0.25 = 1/16) is the slot resolution the offsets are measured on; `cycleBeats` (default 4 = one bar at x/4) is the pattern length that repeats. Onsets are read relative to the clip start, so the groove is independent of where the clip sits. Reversible with edit_undo. Then apply it via the `groove` param on clip_quantize / clip_quantize_audio (pass the returned id or name). Returns {groove}.",
    inputSchema: {
      clipId: external_exports.string().uuid().describe("Id of the clip (MIDI or audio) whose feel to capture, from project_snapshot."),
      name: external_exports.string().min(1).describe('Display name for the saved groove, e.g. "Verse drums feel".'),
      gridBeats: external_exports.number().positive().optional().describe(
        "Slot resolution in beats the offsets are measured on (default 0.25 = 1/16; 0.5 = 1/8). Must be > 0."
      ),
      cycleBeats: external_exports.number().positive().optional().describe("Pattern length in beats that the groove repeats over (default 4 = one bar at x/4). Must be > 0.")
    }
  },
  async ({ clipId, name, gridBeats, cycleBeats }) => toToolResult(() => bridge.send("groove.extract", { clipId, name, gridBeats, cycleBeats }))
);
