registerTool(
  "vc_sidecar_start",
  {
    title: "Start the local voice-conversion sidecar",
    description: "Start the local RVC voice-conversion sidecar (spawns scripts/rvc/run.sh, a FastAPI facade bound to 127.0.0.1:8002 only) if it isn't already healthy, then waits for it to report ready. No params \u2014 safe to call even if it's already starting or healthy (idempotent: a healthy sidecar returns immediately, a boot already in flight is simply observed). Errors with an actionable message if the sidecar was never installed (points at scripts/rvc/install.sh) or if the process exits during startup (points at the log). A slow load is NOT an error \u2014 if the health check doesn't succeed within the startup timeout, this still returns ok with `state: \"starting\"`; call vc_sidecar_status again a little later rather than retrying vc_sidecar_start. Returns the same `{state, message, version?, engine?, baseModelPresent?, voiceCount?, pid?}` shape as vc_sidecar_status.",
    inputSchema: {}
  },
  async () => toToolResult(() => bridge.send("vc.sidecarStart"))
);
registerTool(
  "vc_sidecar_stop",
  {
    title: "Stop the local voice-conversion sidecar",
    description: "Stop the local RVC voice-conversion sidecar (graceful SIGTERM via its pidfile, escalating to a forced kill if it doesn't exit promptly) to free the memory its loaded models hold. No params. Succeeds as a no-op (not an error) if it wasn't running. Returns the same `{state, message, version?, engine?, baseModelPresent?, voiceCount?, pid?}` shape as vc_sidecar_status (state settles to `installedNotRunning`).",
    inputSchema: {}
  },
  async () => toToolResult(() => bridge.send("vc.sidecarStop"))
);
registerTool(
  "vc_convert_vocals",
  {
    title: "Convert vocals to a voice",
    description: `Convert an existing vocal recording to a target voice with the local RVC voice-conversion sidecar. BLOCKS until the conversion finishes (no separate poll/import step \u2014 unlike generate_song, this is a render_mixdown-class call, not an async job) and lands the result as a NEW AI-flagged audio track + clip in the project automatically, in one undoable edit (edit_undo removes it). Call vc_sidecar_start first if vc_sidecar_status isn't healthy. TYPICAL FLOW for "turn this vocal into voice X": generate or import a song, extract_stems with trackNames:["vocals"] (or import an existing a cappella recording), then convert_vocals the resulting vocal clip/file to the target voice. OWN-VOICE-ONLY POLICY: voiceId must be a voice trained from the user's OWN recordings (vc_train_voice) that they have the rights to use \u2014 NEVER a celebrity or third-party voice. The reserved id "base" is a legitimate SMOKE-TEST target: it exercises the full pipeline honestly WITHOUT a real trained voice, and its result always carries realConversion:false plus a note explaining why \u2014 use it to prove the pipeline works end-to-end before any real voice exists. Pass EXACTLY ONE of clipId or path to name the source audio: clipId converts an EXISTING audio clip's FULL backing recording (clip trims/ time-stretch are NOT applied to what gets converted, only to how the RESULT is later placed) and defaults atBeat to that clip's own start beat; path converts a local audio file directly (absolute or ~-expanded) and defaults atBeat to 0. Returns {trackId, clipId, outputPath, realConversion, inputSeconds, inferSeconds, rtf?, sampleRate, note?} \u2014 realConversion is false only for the "base" smoke target, true for a real trained voice.`,
    inputSchema: {
      clipId: external_exports.string().optional().describe(
        "Id of an existing AUDIO clip whose FULL backing recording gets converted (from project_snapshot or a prior clip_add_audio/import result). Pass EXACTLY ONE of clipId or path \u2014 passing both, or neither, is rejected. A MIDI clip's id is rejected (no audio to convert)."
      ),
      path: external_exports.string().optional().describe(
        "Absolute or ~-expanded local path to an audio file to convert directly. Pass EXACTLY ONE of clipId or path \u2014 passing both, or neither, is rejected."
      ),
      voiceId: external_exports.string().min(1).describe(
        `The target voice's id: either a real voice trained from the user's OWN recordings (vc_train_voice; own-voice-only, never a celebrity or third-party voice), or the reserved smoke-test id "base" (untrained generic synthesizer \u2014 proves the pipeline runs, NOT a real voice conversion; its result always carries realConversion:false plus an explanatory note).`
      ),
      pitchSemitones: external_exports.number().int().min(-24).max(24).optional().describe(
        "Pitch shift applied during conversion, in semitones (+12 = up an octave). Integer, -24..24. Omit for no shift (0)."
      ),
      trackName: external_exports.string().optional().describe('Name for the new track/clip. Omit for a default like "Voice: <voiceId>".'),
      atBeat: external_exports.number().min(0).optional().describe(
        "Where the converted clip lands, in beats (quarter notes) from timeline start. Omit to default to the source clip's own start beat (clipId form) or 0 (path form)."
      )
    }
  },
  async ({ clipId, path: path6, voiceId, pitchSemitones, trackName, atBeat }) => toToolResult(
    () => bridge.send("vc.convertVocals", { clipId, path: path6, voiceId, pitchSemitones, trackName, atBeat })
  )
);
registerTool(
  "vc_train_voice",
  {
    title: "Train a new voice from the user's own recordings",
    description: 'Train a new voice for vc_convert_vocals from a local directory of clean, dry vocal recordings. OWN-VOICE-ONLY POLICY: datasetDir must contain ONLY recordings the user has the rights to use as their own voice (or a voice they have explicit permission for) \u2014 NEVER a celebrity or third-party voice; this tool implies no product-compatibility claim about the underlying engine. TODAY this always answers a reserved "training not yet available" error (the facade validates the request shape, then answers that the feature ships with a later roadmap item, the in-app Voice panel) \u2014 call it anyway if a user asks to train a voice; the error IS the honest, actionable answer, not a bug. Use the "base" smoke-test target on vc_convert_vocals in the meantime to prove the pipeline itself works.',
    inputSchema: {
      name: external_exports.string().min(1).describe("Display name for the new voice."),
      datasetDir: external_exports.string().min(1).describe(
        "Absolute or ~-expanded local directory of the user's OWN clean, dry vocal recordings to train from (own-voice-only \u2014 never a celebrity or third-party voice)."
      ),
      voiceId: external_exports.string().optional().describe("Specific id for the new voice. Omit to let the facade derive one from name."),
      epochs: external_exports.number().int().positive().optional().describe("Training-length override, in epochs. Omit for the facade's default.")
    }
  },
  async ({ name, datasetDir, voiceId, epochs }) => toToolResult(() => bridge.send("vc.trainVoice", { name, datasetDir, voiceId, epochs }))
);
registerTool(
  "vc_list_voices",
  {
    title: "List the available conversion voices",
    description: 'List every voice the local RVC voice-conversion sidecar can convert to (for vc_convert_vocals\'s voiceId). No params. Returns `{voices: [{id, name, state, hasIndex?, createdAt?, kind?, trained?, note?}]}` \u2014 the sidecar\'s own descriptors verbatim. The reserved id "base" is ALWAYS listed (kind "builtin", trained false, plus a note): it is the pipeline SMOKE-TEST target, not a real voice \u2014 converting to it proves the pipeline runs and always carries realConversion:false. Real voices appear here once trained (vc_train_voice \u2014 arriving with a later update). `state` is "ready" (usable now), "needsConversion" (trained but not yet prepared for this engine), or "incomplete". Requires the sidecar to be running \u2014 call vc_sidecar_start first if vc_sidecar_status isn\'t healthy; an unreachable sidecar errors with the actionable next step, never a bare connection failure. OWN-VOICE-ONLY POLICY: any real voice listed here was trained from the user\'s OWN recordings that they have the rights to use \u2014 NEVER a celebrity or third-party voice model.',
    inputSchema: {}
  },
  async () => toToolResult(() => bridge.send("vc.listVoices"))
);
server.registerTool(
  "ai_provider_status",
  {
    title: "Check which cloud AI providers have a key configured",
    description: 'Report whether each cloud AI provider (anthropic, openai, suno) has a usable API key in the running app, and where it comes from. No params. Returns `{providers: [{provider, configured, source}]}` where `source` is `"env"` (an environment variable \u2014 takes precedence and is read-only from the app), `"keychain"` (set in the app\'s Settings panel), or `"none"` (not set). An entry may also carry `consentRequired: true` \u2014 the key IS stored (configured=true, source keychain) but macOS will show a one-time access prompt the first time it is actually used. ACE-Step is the LOCAL, KEYLESS song sidecar and never appears here \u2014 use ai_sidecar_status for it. IMPORTANT: this is STATUS ONLY. Key VALUES are never exposed and can NOT be set over MCP or the control protocol (this traffic is logged in your conversation, so a secret must never cross it). If a provider is `none`, tell the user to set it via the app\'s Settings panel (\u2318,) or an environment variable \u2014 do not ask them to paste a key to you.'
  },
  async () => toToolResult(() => bridge.send("ai.providerStatus"))
);
registerTool(
  "ai_write_lyrics",
  {
    title: "Write or refine lyrics in the app (project-aware)",
    description: "Write (or REFINE) section-labeled lyrics in ACE-Step's bracketed-structure format ([verse]/[chorus]/[bridge]/[outro] on their own line, lyric lines beneath) using the RUNNING APP's configured provider and its LIVE project context. This routes through the DAW (bridge.send), so it uses the keys managed in the app's Settings panel (Anthropic preferred, OpenAI fallback) and, when you omit `context`, defaults the key/tempo/time-signature from the current project \u2014 the words come back fit to the session. This is different from `generate_lyrics`, which calls Anthropic/OpenAI DIRECTLY from the MCP server's OWN process environment and knows nothing about the open project; prefer THIS tool when a DAW project is open, and feed its `lyrics` output straight into `generate_song`. Returns `{lyrics, provider}` (provider is \"anthropic\" or \"openai\"). If NEITHER provider has a key in the app, it errors with an actionable message pointing at the app's Settings panel (\u2318,) and ai_provider_status \u2014 key values are never sent over this channel, so ask the user to set one there rather than pasting it to you.",
    inputSchema: {
      prompt: external_exports.string().min(1).describe('The theme \u2014 what the song is about, e.g. "missing someone after they moved away".'),
      style: external_exports.string().optional().describe('Optional style/genre guidance, e.g. "90s pop-punk", "slow R&B ballad".'),
      structure: external_exports.array(external_exports.string()).optional().describe(
        'Optional ordered section tags, e.g. ["verse","chorus","verse","chorus","bridge","chorus"]. Defaults to a familiar pop structure when omitted.'
      ),
      context: external_exports.object({
        keyScale: external_exports.string().optional().describe('Key/scale, e.g. "C Major", "A Minor".'),
        tempoBPM: external_exports.number().optional().describe("Tempo in BPM."),
        timeSignature: external_exports.string().optional().describe('Time signature, e.g. "4/4", "3/4".'),
        genre: external_exports.string().optional().describe("Genre/feel hint.")
      }).optional().describe(
        "Optional project-musical context. ANY field you omit defaults from the current project (tempoBPM/timeSignature from the transport), so a bare call still fits the session."
      ),
      existingLyrics: external_exports.string().optional().describe(
        "REFINE mode: the current lyrics to revise. Provide this together with `instruction` to revise rather than write from scratch."
      ),
      instruction: external_exports.string().optional().describe('REFINE mode: how to revise, e.g. "make the chorus more hopeful".')
    }
  },
  async (params) => toToolResult(() => bridge.send("ai.writeLyrics", params))
);
registerTool(
  "generate_song",
  {
    title: "Generate a full song locally (ACE-Step)",
    description: 'Submit an async full-song generation job to the LOCAL ACE-Step-1.5 sidecar \u2014 sung vocals + instrumentation together from a style prompt and optional lyrics, fully offline (no API key, no cloud). Returns immediately with `{jobId, state, queuePosition?}` (state is always "queued"); the song is NOT ready yet \u2014 poll generation_status with the returned jobId until it reports "succeeded", then import the resulting audioPath with clip_add_audio. REQUIRES the sidecar to be healthy first \u2014 call ai_sidecar_status (and ai_sidecar_start if needed) before this, or expect an actionable error pointing at whichever of those two you skipped.',
    inputSchema: {
      prompt: external_exports.string().min(1).describe(
        'Style/caption text: genre, mood, instrumentation, era, production style, vocal character \u2014 e.g. "80s synth-pop, anthemic, driving bassline, female vocals".'
      ),
      lyrics: external_exports.string().optional().describe(
        "Section-labeled lyrics in ACE-Step's bracketed-structure format \u2014 bracketed tags on their own line (e.g. [Verse 1], [Pre-Chorus], [Chorus], [Bridge], [Outro]), optionally with a style qualifier like [Chorus - anthemic] or [whispered], followed by the lyric lines for that section (parentheses mark backing vocals). 6-10 syllables/line reads most naturally. Example:\n[Verse 1]\nWalking home in the rain\nThinking of you again\n[Chorus]\nWe rise together (together)\nThrough the storm and the weather\nOmit (or leave blank) for an INSTRUMENTAL track \u2014 generate_lyrics can write this for you first."
      ),
      durationSeconds: external_exports.number().min(10).max(600).optional().describe(
        `Target length in seconds. Omit to use ACE-Step's own default (30s). The documented "stable" range is roughly 30-240s \u2014 longer generations show more structural drift/repetition per ACE-Step's own docs.`
      ),
      seed: external_exports.number().int().min(0).optional().describe(
        "Deterministic seed for reproducible output. Omit for a fresh random seed each call; reuse the same seed + inputs later to reproduce a prior render."
      ),
      bpm: external_exports.number().min(30).max(300).optional().describe("Target tempo in beats per minute. Omit to let ACE-Step choose one that fits the prompt."),
      keyScale: external_exports.string().optional().describe('Free-text key/scale hint, e.g. "C Major", "A Minor".'),
      timeSignature: external_exports.string().optional().describe('Free-text time-signature hint, e.g. "4/4", "3/4".'),
      vocalLanguage: external_exports.string().optional().describe('Language code for sung vocals, e.g. "en", "ja", "es". Defaults to "en".'),
      guidanceScale: external_exports.number().min(1).max(20).optional().describe(
        "Classifier-free-guidance scale \u2014 higher follows the prompt/lyrics more strictly, at some cost to naturalness. Omit to use ACE-Step's default (7.0)."
      ),
      inferenceSteps: external_exports.number().int().min(1).max(100).optional().describe(
        "Diffusion sampling steps \u2014 more steps can improve quality at the cost of generation time. Omit to use ACE-Step's turbo-model default (8)."
      )
    }
  },
  async (params) => toToolResult(() => bridge.send("ai.generateSong", params))
);
server.registerTool(
  "generation_status",
  {
    title: "Poll a local song-generation job",
    description: 'Poll a song-generation job previously submitted with generate_song. Returns `{jobId, state, progress?, stage?, statusText?, audioPath?}` \u2014 `state` is one of "queued", "running", or "succeeded" (a job that failed upstream surfaces as a TOOL ERROR here instead, with the sidecar\'s own failure detail, e.g. an out-of-memory message \u2014 it is never returned as a quiet "failed" state). `progress` (0-1) and `stage`/`statusText` are best-effort informational detail from the sidecar, when it reports them. The FIRST poll that observes `state == "succeeded"` fetches the finished audio to a local file and reports it as `audioPath`; later polls of the same jobId reuse that same cached path (no repeated downloads). Once `audioPath` is present, import it onto a track with clip_add_audio (create the track first with track_add if you don\'t already have one). Poll every 5-10 seconds, not in a tight loop \u2014 generation commonly takes minutes.',
    inputSchema: {
      jobId: external_exports.string().min(1).describe("The jobId returned by generate_song.")
    }
  },
  async ({ jobId }) => toToolResult(() => bridge.send("ai.generationStatus", { jobId }))
);
registerTool(
  "import_generation",
  {
    title: "Import a finished generation into the project",
    description: 'Turn a FINISHED song-generation job into project material: creates a new AI-flagged audio track + clip (violet in the UI) from the generated audio, and optionally adopts the project tempo from the generation\'s detected BPM \u2014 all as ONE undoable step (edit_undo removes the track AND restores the tempo together). This is the final step of the generation flow: generate_song -> poll generation_status until it reports state "succeeded" (an audioPath is present) -> import_generation -> then arrange/edit with the normal clip_* / track_* commands. Do NOT call this before the job succeeds: a still-running job returns an actionable error telling you to keep polling generation_status; an unknown/expired jobId returns the same expired-job error generation_status would. Returns `{trackId, clipId, adoptedTempoBPM?}` (adoptedTempoBPM is present only when the tempo was actually changed).',
    inputSchema: {
      jobId: external_exports.string().min(1).describe(
        'The jobId returned by generate_song. The job must have reached state "succeeded" (check with generation_status) \u2014 otherwise this errors.'
      ),
      trackName: external_exports.string().optional().describe(
        'Name for the new track. Omit to default to "AI: <first words of the prompt>".'
      ),
      atBeat: external_exports.number().min(0).optional().describe("Beat position where the clip lands. Omit for 0 (the start of the timeline)."),
      setProjectTempo: external_exports.boolean().optional().describe(
        "Whether to set the project tempo to the generation's detected BPM. Omit to auto-adopt ONLY when the project has no other clips yet (so the first imported track establishes the grid, but a later import never silently moves everything). true forces adoption; false forbids it. Adoption also requires the generation to report a BPM."
      )
    }
  },
  async (params) => toToolResult(() => bridge.send("ai.importGeneration", params))
);
registerTool(
  "extract_stems",
  {
    title: "Separate an existing audio file into named stems (ACE-Step)",
    description: "Submit an async stem-SEPARATION job to the LOCAL ACE-Step-1.5 sidecar: pulls the requested named tracks (e.g. vocals, drums, bass) out of an existing mixed-down audio file, fully offline. Internally submits one upstream job per requested track name (ACE-Step's `extract` task type separates one track per call) and returns a single COMPOSITE `{jobId, state, trackNames}` grouping them (state is always \"queued\"). Poll with generation_status using the returned jobId exactly like generate_song; a succeeded poll's `stems` array carries every separated track's local audioPath. Then call import_generated_stems to land them as N violet AI tracks in one step. REQUIRES the sidecar to be healthy first \u2014 call ai_sidecar_status (and ai_sidecar_start if needed).",
    inputSchema: {
      sourceAudioPath: external_exports.string().min(1).describe(
        "Local filesystem path to the existing mixed-down audio file to separate (e.g. a rendered mixdown from render_mixdown, or any readable audio file on this machine). The sidecar only accepts source audio it can read via its own temp-directory allowlist; the tool stages a copy for you, so any readable local path works."
      ),
      trackNames: external_exports.array(external_exports.string().min(1)).min(1).describe(
        `Stem names to extract, e.g. ["vocals", "drums", "bass"]. ACE-Step's fixed vocabulary: woodwinds, brass, fx, synth, strings, percussion, keyboard, guitar, bass, drums, backing_vocals, vocals. An unrecognized name is rejected by the sidecar with its own error.`
      ),
      model: external_exports.string().optional().describe(
        'DiT model name to use, e.g. "acestep-v15-xl-sft". OPTIONAL and normally best left unset (M6 iii-c-real): extraction is a BASE-model-only capability, but omitting this does NOT fall back to turbo \u2014 the app defaults it to its own stems model and auto-loads that model into a handler slot before submitting if needed (can take minutes the first time a given model loads). Pass this explicitly only to request a different DiT model.'
      )
    }
  },
  async (params) => toToolResult(() => bridge.send("ai.extractStems", params))
);
registerTool(
  "lego_generate",
  {
    title: "Generate new tracks that fit existing audio (ACE-Step Lego)",
    description: "Submit an async per-track GENERATION job to the LOCAL ACE-Step-1.5 sidecar: writes NEW instrument/vocal tracks (e.g. a bass line, a synth pad) so each fits an existing source audio's musical context \u2014 ACE-Step's \"Lego\" task, building a song up one layer at a time. Each requested track carries its own local `prompt` (that track's specific description) alongside a shared `globalCaption` (the full song's description) \u2014 both feed the same generation. Internally submits one upstream job per requested track (same one-job-per-track shape as extract_stems) and returns a single COMPOSITE `{jobId, state, trackNames}`. Poll with generation_status exactly like generate_song/extract_stems; a succeeded poll's `stems` array carries every generated track's local audioPath. Then call import_generated_stems to land them as N violet AI tracks in one step. REQUIRES the sidecar to be healthy first \u2014 call ai_sidecar_status (and ai_sidecar_start if needed).",
    inputSchema: {
      sourceAudioPath: external_exports.string().min(1).describe(
        "Local filesystem path to the existing audio the new tracks must musically fit (e.g. a mixdown of the tracks so far). Same staging semantics as extract_stems."
      ),
      globalCaption: external_exports.string().min(1).describe(
        'Shared, song-level description used for every requested track, e.g. "warm lofi hip-hop, 90 bpm, dusty vinyl texture".'
      ),
      tracks: external_exports.array(
        external_exports.object({
          trackName: external_exports.string().min(1).describe(
            "The track to generate, from ACE-Step's fixed vocabulary: woodwinds, brass, fx, synth, strings, percussion, keyboard, guitar, bass, drums, backing_vocals, vocals."
          ),
          prompt: external_exports.string().optional().describe(
            `This track's OWN local description, e.g. "round sub bass, laid back, syncopated". Omit for a bare generic instruction.`
          )
        })
      ).min(1).describe("The tracks to generate \u2014 one entry per new track, each with its own local prompt."),
      model: external_exports.string().optional().describe(
        'DiT model name to use, e.g. "acestep-v15-xl-sft". OPTIONAL \u2014 same default-model + auto-load behavior as extract_stems\' `model` note; leave unset for the normal case.'
      )
    }
  },
  async (params) => toToolResult(() => bridge.send("ai.legoGenerate", params))
);
registerTool(
  "import_generated_stems",
  {
    title: "Import a finished stems/Lego job as N tracks",
    description: 'Turn a FINISHED extract_stems or lego_generate job into project material: creates N new AI-flagged audio tracks + clips (violet in the UI), one per named stem/track, all at the same beat position, and optionally adopts the project tempo from the first track (in submission order) that reports a BPM \u2014 all as ONE undoable step (edit_undo removes EVERY imported track, and restores the tempo, together). This is the final step of the stems/Lego flow: extract_stems or lego_generate -> poll generation_status until it reports state "succeeded" with a non-empty `stems` array -> import_generated_stems -> then arrange/edit the new tracks with the normal clip_* / track_* commands. Do NOT call this before every track has succeeded: a still-running job returns an actionable error telling you to keep polling generation_status; an unknown/ expired jobId returns the same expired-job error generation_status would. Returns `{tracks: [{trackId, clipId, trackName}, ...], adoptedTempoBPM?}` (adoptedTempoBPM is present only when the tempo was actually changed).',
    inputSchema: {
      jobId: external_exports.string().min(1).describe(
        'The composite jobId returned by extract_stems or lego_generate. Every underlying track must have reached state "succeeded" (check with generation_status) \u2014 otherwise this errors.'
      ),
      atBeat: external_exports.number().min(0).optional().describe(
        "Beat position where every imported clip lands (they share one start \u2014 stems are meant to play together). Omit for 0 (the start of the timeline)."
      ),
      setProjectTempo: external_exports.boolean().optional().describe(
        "Whether to set the project tempo to the detected BPM. Omit to auto-adopt ONLY when the project has no other clips yet. true forces adoption; false forbids it. Adoption also requires at least one imported track to report a BPM."
      )
    }
  },
  async (params) => toToolResult(() => bridge.send("ai.importGeneratedStems", params))
);
registerTool(
  "ai_repaint_audio",
  {
    title: "Repaint a window of existing audio in place (ACE-Step)",
    description: 'Submit an async REPAINT job to the LOCAL ACE-Step-1.5 sidecar: re-renders a WINDOW of an EXISTING audio file in place (a \'part swap\'/inpainting job) \u2014 everything outside [start, end) stays untouched, fully offline. Unlike extract_stems/lego_generate this is a SINGLE upstream job (no per-track fan-out, no composite jobId). Returns immediately with `{jobId, state, queuePosition?}` (state is always "queued"); poll generation_status with the returned jobId exactly like generate_song until it reports "succeeded" \u2014 its audioPath is then the FULL-LENGTH file with the window repainted (import with clip_add_audio, or use it to replace the source). There is NO separate retake tool: to get a different take of the SAME window, call ai_repaint_audio again with the same sourcePath/start/end and OMIT seed (a fresh random seed each call). REQUIRES the sidecar to be healthy first \u2014 call ai_sidecar_status (and ai_sidecar_start if needed).',
    inputSchema: {
      sourcePath: external_exports.string().min(1).describe(
        "Local filesystem path to the existing audio file whose window gets repainted (e.g. a rendered mixdown from render_mixdown, or any readable audio file on this machine). Must exist on disk. The sidecar only accepts source audio it can read via its own temp-directory allowlist; the tool stages a copy for you, so any readable local path works."
      ),
      start: external_exports.number().min(0).describe("Start of the window to repaint, in seconds from the top of the file."),
      end: external_exports.number().optional().describe(
        "End of the window, in seconds. Must be greater than start. Omit to repaint from start through the end of the file."
      ),
      prompt: external_exports.string().optional().describe(
        `Style/caption text guiding the repainted window, e.g. "driving rock drums, tighter groove". Omit to keep the source's own musical context.`
      ),
      lyrics: external_exports.string().optional().describe(
        "Section-labeled lyrics (ACE-Step bracketed-structure format) for the repainted window, when it carries vocals. Omit/blank leaves the window's vocal content to the model."
      ),
      mode: external_exports.enum(["conservative", "balanced", "aggressive"]).optional().describe(
        'How strongly to regenerate the window: "conservative" stays closest to the original audio, "balanced" (default) is the standard trade-off and the ONLY mode where `strength` has any effect, "aggressive" most freely reimagines the window.'
      ),
      strength: external_exports.number().min(0).max(1).optional().describe(
        `0-1 \u2014 how far a "balanced"-mode repaint is allowed to depart from the original audio in the window. Only consulted when mode is "balanced" (the default). Omit to use the sidecar's own default.`
      ),
      wavCrossfadeSec: external_exports.number().min(0).optional().describe(
        "Crossfade applied at the window edges in the rendered WAV, in seconds, to smooth the seam. Omit for the sidecar's own default (0.0 \u2014 no crossfade)."
      ),
      seed: external_exports.number().int().min(0).optional().describe(
        "Deterministic seed for reproducible output. Omit for a fresh random seed each call \u2014 this is how you RETAKE the same window: call again with the same sourcePath/start/end and no seed."
      ),
      model: external_exports.string().optional().describe(
        `DiT model name override, e.g. "acestep-v15-xl-sft". OPTIONAL and normally best left unset: unlike extract_stems/lego_generate, repaint also works on the sidecar's default turbo tier, so omitting this needs no auto-load step.`
      )
    }
  },
  async (params) => toToolResult(() => bridge.send("ai.repaintAudio", params))
);
registerTool(
  "ai_fix_clip_region",
  {
    title: "Fix a region of a clip with AI (submit)",
    description: `Submit an AI REPAINT of a REGION of an existing timeline clip (M6 v-b, the 'fix this phrase with AI' flow) to the LOCAL ACE-Step-1.5 sidecar. SUBMIT-ONLY: this bounces a dry, as-heard window of the target material (the region plus contextSeconds of padding each side, clamped to the clip/comp span), submits it, and returns IMMEDIATELY \u2014 it does NOT change the project. This is step 1 of a three-step flow: ai_fix_clip_region -> poll ai_generation_status with the returned jobId until state "succeeded" -> ai_import_clip_fix to land it. The result lands as a VIOLET take LANE comped in over EXACTLY [startBeat, endBeat) \u2014 the original audio is never replaced and the comp elsewhere is untouched (a comp splice); use the take_* tools to comp further between the takes afterwards. To RETAKE, call this again with the SAME region and OMIT seed (a fresh random seed each call). Pending fixes are in-memory only and DIE with the app process (and on a project switch). REQUIRES the sidecar to be healthy \u2014 call ai_sidecar_status (and ai_sidecar_start if needed). Returns a placement echo {jobId, state, queuePosition?, windowStartBeat, windowEndBeat, regionStartBeat, regionEndBeat, repaintStartSeconds, repaintEndSeconds, bouncePath}.`,
    inputSchema: {
      trackId: external_exports.string().min(1).describe("Id of the track holding the clip to fix."),
      clipId: external_exports.string().min(1).describe(
        "Id of the AUDIO clip to fix (from project_snapshot). A MIDI clip is rejected. The clip may be a plain clip or an existing comp member \u2014 either works."
      ),
      startBeat: external_exports.number().describe(
        "Start of the region to repaint, in ABSOLUTE timeline beats (the same space as clip_split/clip_move). Must lie inside the target clip/comp span."
      ),
      endBeat: external_exports.number().describe(
        "End of the region to repaint, in ABSOLUTE timeline beats. Must be greater than startBeat and inside the span. The region must be at least 0.1 s long."
      ),
      prompt: external_exports.string().optional().describe(
        `Style/caption text guiding the repainted region, e.g. "clearer vocal, on pitch". Omit to keep the source's own musical context.`
      ),
      lyrics: external_exports.string().optional().describe(
        "Section-labeled lyrics (ACE-Step bracketed-structure format) for the region, when it carries vocals. Omit/blank leaves the vocal content to the model."
      ),
      mode: external_exports.enum(["conservative", "balanced", "aggressive"]).optional().describe(
        'How strongly to regenerate the region: "conservative" stays closest to the original, "balanced" (default) is the standard trade-off and the ONLY mode where strength has any effect, "aggressive" most freely reimagines the region.'
      ),
      strength: external_exports.number().min(0).max(1).optional().describe(
        `0-1 \u2014 how far a "balanced"-mode fix may depart from the original in the region. Only consulted when mode is "balanced". Omit for the sidecar's own default.`
      ),
      seed: external_exports.number().int().min(0).optional().describe(
        "Deterministic seed. OMIT for a fresh random seed each call \u2014 this is how you RETAKE the same region: call again with the same startBeat/endBeat and no seed."
      ),
      contextSeconds: external_exports.number().min(1).max(60).optional().describe(
        "Seconds of surrounding audio rendered each side of the region for boundary continuity (clamped to the clip/comp span). Default 10. Larger = more context but a longer job."
      ),
      model: external_exports.string().optional().describe(
        "DiT model name override. OPTIONAL and normally best left unset (repaint works on the sidecar's default turbo tier, like ai_repaint_audio)."
      )
    }
  },
  async (params) => toToolResult(() => bridge.send("ai.fixClipRegion", params))
);
registerTool(
  "ai_import_clip_fix",
  {
    title: "Import a finished clip fix (land the take)",
    description: 'Land a FINISHED clip fix (M6 v-b) as a VIOLET take LANE comped in over EXACTLY the region requested by ai_fix_clip_region. This is step 3 of the flow: ai_fix_clip_region -> poll ai_generation_status until "succeeded" -> ai_import_clip_fix. The original audio is NEVER replaced and the comp elsewhere is untouched (a comp splice of the fix region only) \u2014 one undoable "AI Fix Take" edit (edit_undo restores the plain clip / previous comp). Comp between the takes afterwards with the take_* tools. Do NOT call before the job has succeeded: a still-running job returns an actionable error telling you to keep polling ai_generation_status; an unknown jobId (pending fixes die with the app process or on a project switch) returns an error telling you to submit again with ai_fix_clip_region; a target that drifted beyond a pure move (re-trimmed/re-stretched/re-gained, or the tempo changed) returns a "stale" error naming what changed. Returns {trackId, groupId, laneId, laneName ("AI Fix N"), group} \u2014 the take group with its lanes and comp.',
    inputSchema: {
      jobId: external_exports.string().min(1).describe(
        'The jobId returned by ai_fix_clip_region. The job must have reached state "succeeded" (check with ai_generation_status) \u2014 otherwise this errors.'
      )
    }
  },
  async (params) => toToolResult(() => bridge.send("ai.importClipFix", params))
);
registerTool(
  "ai_copilot_send",
  {
    title: "Send a message to the in-app AI copilot",
    description: 'Drives the IN-APP copilot, which executes DAW commands itself against a curated subset of this same command surface (tracks, clips, transport, mixer, takes, rendering, AI generation, undo \u2014 NOT project open/save/new or track removal, which stay human-initiated). Prefer the DIRECT tools above for direct edits; use this to delegate a whole musical task in one instruction (e.g. "add a drum track and program a 2-bar house beat") or to test the copilot itself. The copilot CANNOT call itself \u2014 its catalog excludes ai_copilot_send/state/reset, so recursion is impossible. Returns immediately with `{turnId, status: "running"}`; the turn runs asynchronously \u2014 poll ai_copilot_state with the returned turnId until its status is done/failed/cancelled. Errors if a turn is already running (poll or ai_copilot_reset first) or if the app has no AI provider configured (points at the app\'s Settings panel).',
    inputSchema: {
      message: external_exports.string().min(1).describe('The instruction to send to the copilot, e.g. "add a bassline on the Bass track".'),
      maxRounds: external_exports.number().int().min(1).max(32).optional().describe(
        "Bound THIS reply's tool-call rounds, 1-32 (clamped), overriding the in-app copilot setting for this turn only \u2014 the app's own default is 8. Lower it (e.g. 2-3) for a cheap, single-step ask so a wandering turn can't run long; raise it (e.g. 16-32) for a complex multi-track arrangement that needs many rounds of tool calls to finish. Omit to use the user's configured setting. See ai_copilot_state's `limits` for the effective value and the full policy."
      )
    }
  },
  async ({ message, maxRounds }) => toToolResult(() => bridge.send("ai.copilotSend", { message, maxRounds }))
);
server.registerTool(
  "ai_copilot_state",
  {
    title: "Poll the in-app AI copilot's state",
    description: 'Poll the in-app copilot\'s session state (the ai_generate_song / ai_generation_status poll precedent). Returns `{status, currentTurnId?, transcript, limits}` where `status` is one of "idle", "running", "done", "failed", "cancelled", and `transcript` is an array of entries `{id, turnId, kind, text?, command?, ok?, summary?}` \u2014 `kind` is one of "user" (your message), "assistant" (the copilot\'s reply text), "toolCall" (a DAW command it invoked), "toolResult" (that command\'s outcome), or "failure" (a turn-level error). `limits` is `{maxRounds, defaultMaxRounds, validMin, validMax}` \u2014 the effective per-turn tool-round budget (the app setting, or the last ai_copilot_send call\'s `maxRounds` override) alongside the app\'s built-in default (8) and the valid range (1-32), so you can introspect the budget without guessing. Also carries the CURRENT conversation\'s identity (chat-persist design): `chatId` (always present \u2014 the id this conversation would archive under), `chatTitle` (present once derived from the first message, or after a rename), and `droppedEntries` (present only when a resumed conversation had earlier messages trimmed to fit the project file, > 0). Call ai_copilot_send first to get a turnId.',
    inputSchema: {
      turnId: external_exports.string().optional().describe(
        "Filter the transcript to one turn, from ai_copilot_send. Omit for the whole session's transcript. An unknown/expired turnId is not an error \u2014 it returns the copilot's current status with an empty transcript."
      )
    }
  },
  async ({ turnId }) => toToolResult(() => bridge.send("ai.copilotState", { turnId }))
);
registerTool(
  "ai_copilot_reset",
  {
    title: "Reset the in-app AI copilot",
    description: "Cancel any in-flight copilot turn, ARCHIVE the current conversation into the project's saved chat history (it is never destroyed \u2014 see ai_copilot_chats/ai_copilot_resume_chat), and start a fresh empty chat. No params. Use this to start a fresh conversation, or to recover from a stuck/looping turn. Returns `{archivedChatId?, evictedChatId?}` \u2014 `archivedChatId` is present when there was a conversation to archive; `evictedChatId` is present only on the rare occasion archiving pushed the project past its saved-chat cap and the oldest one had to be dropped (never silent). Both absent (an empty result) is normal for a chat that was already empty.",
    inputSchema: {}
  },
  async () => toToolResult(() => bridge.send("ai.copilotReset"))
);
server.registerTool(
  "ai_copilot_get_model",
  {
    title: "Read the in-app AI copilot's current model + the curated model catalog",
    description: 'Reads which Anthropic model the in-app copilot currently targets, plus the full curated picker it\'s chosen from. Returns `{model, catalog}` where `catalog` is an array of `{id, name, note}` \u2014 pass any `id` from it to ai_copilot_set_model. `model` defaults to "claude-sonnet-5" (balanced) until changed.',
    inputSchema: {}
  },
  async () => toToolResult(() => bridge.send("ai.copilotGetModel"))
);
registerTool(
  "ai_copilot_set_model",
  {
    title: "Set the in-app AI copilot's model",
    description: 'Sets which Anthropic model the in-app copilot targets for SUBSEQUENT turns (an in-flight turn already resolved its provider, so this never retargets one mid-flight). `model` must be one of the curated ids from ai_copilot_get_model\'s `catalog` (e.g. "claude-sonnet-5" for balanced default use, "claude-opus-4-8" for the highest-reasoning flagship, "claude-haiku-4-5" for the fastest/cheapest option) \u2014 an unrecognized id errors with the full list of valid ids rather than silently falling back. Returns `{model}` echoing the now-effective model.',
    inputSchema: {
      model: external_exports.string().min(1).describe(
        'A curated model id from ai_copilot_get_model\'s `catalog`, e.g. "claude-sonnet-5".'
      )
    }
  },
  async ({ model }) => toToolResult(() => bridge.send("ai.copilotSetModel", { model }))
);
server.registerTool(
  "ai_copilot_chats",
  {
    title: "List the in-app AI copilot's saved conversations",
    description: "List every saved copilot conversation in the OPEN project \u2014 conversations live INSIDE the project file (chat-persist design), so this always reflects the current project, not a global history. No params. Returns `{chats: [{chatId, title, createdAt, updatedAt, entryCount, model?, active?, droppedEntries?}], activeChatId}`, sorted newest-first by `updatedAt`. `active: true` marks the copilot's CURRENT conversation and is only present on that row (it's also only listed once it has at least one message \u2014 a brand-new empty chat isn't noise-listed); `activeChatId` is always present, even if the active chat isn't in `chats` yet. `droppedEntries` appears only when earlier messages of that conversation were trimmed to keep the project file a reasonable size (an honesty counter, never silent). Pass any `chatId` from here to ai_copilot_resume_chat / ai_copilot_delete_chat / ai_copilot_rename_chat.",
    inputSchema: {}
  },
  async () => toToolResult(() => bridge.send("ai.copilotChats"))
);
registerTool(
  "ai_copilot_resume_chat",
  {
    title: "Resume a saved copilot conversation",
    description: 'Resume a previously saved copilot conversation so you can continue it with ai_copilot_send. RESUME IS ALWAYS EXPLICIT \u2014 the copilot never auto-resumes: ai_copilot_reset and reopening a project both leave it on a fresh empty chat, and it stays there until this tool is called. The CURRENT conversation is archived first if it holds any messages (never lost \u2014 its id comes back as `archivedChatId` when that happened). Safe to do after switching models: a saved conversation never carries hidden chain-of-thought, so any curated model can pick it back up. Returns `{chatId, title, entryCount, droppedEntries?, status: "idle", archivedChatId?}` (`droppedEntries`/`archivedChatId` present only when non-zero/applicable). Fails with a teaching error if a turn is currently running (finish it or call ai_copilot_reset first) or for an unrecognized chatId \u2014 list current ones with ai_copilot_chats.',
    inputSchema: {
      chatId: external_exports.string().uuid().describe("The conversation to resume \u2014 a `chatId` from ai_copilot_chats.")
    }
  },
  async ({ chatId }) => toToolResult(() => bridge.send("ai.copilotResumeChat", { chatId }))
);
registerTool(
  "ai_copilot_delete_chat",
  {
    title: "Permanently delete a saved copilot conversation",
    description: "Permanently deletes one saved copilot conversation \u2014 the ONLY destructive chat-history operation (resuming and renaming never destroy anything). Deleting the CURRENTLY ACTIVE conversation is allowed only while no turn is running: it drops that conversation for good and starts a fresh empty chat (`wasActive: true` in the result). Deleting an archived (not currently active) conversation is allowed at any time. Returns `{deleted: true, chatId, wasActive}`. Fails with a teaching error for an unrecognized chatId (list current ones with ai_copilot_chats), or when targeting the active chat while a turn is running (cancel it first with ai_copilot_reset, or wait for it to finish).",
    inputSchema: {
      chatId: external_exports.string().uuid().describe(
        "The conversation to delete \u2014 a `chatId` from ai_copilot_chats. This cannot be undone."
      )
    }
  },
  async ({ chatId }) => toToolResult(() => bridge.send("ai.copilotDeleteChat", { chatId }))
);
registerTool(
  "ai_copilot_rename_chat",
  {
    title: "Rename a saved copilot conversation",
    description: "Renames a saved copilot conversation, active or archived. Titles longer than 120 characters are clamped, never rejected. Returns `{chatId, title}` echoing the stored (possibly clamped) title. Fails with a teaching error for an unrecognized chatId (list current ones with ai_copilot_chats), or for a title that's empty (or only whitespace).",
    inputSchema: {
      chatId: external_exports.string().uuid().describe("The conversation to rename \u2014 a `chatId` from ai_copilot_chats."),
      title: external_exports.string().min(1).describe(
        'New title for the conversation, e.g. "funky bassline idea". Over 120 characters is clamped, not rejected; whitespace-only is rejected.'
      )
    }
  },
  async ({ chatId, title }) => toToolResult(() => bridge.send("ai.copilotRenameChat", { chatId, title }))
);
server.registerTool(
  "generate_lyrics",
  {
    title: "Generate song lyrics",
    description: "Generate section-labeled song lyrics (e.g. [Verse 1], [Chorus], [Bridge]) from a theme, optional style/genre, and optional structure. Uses Anthropic (Claude) if ANTHROPIC_API_KEY is set, otherwise falls back to OpenAI if OPENAI_API_KEY is set. Requires at least one of those keys in the environment/.env.",
    inputSchema: {
      theme: external_exports.string().min(1).describe('What the song is about, e.g. "missing someone after they moved away".'),
      style: external_exports.string().optional().describe('Optional style/genre guidance, e.g. "90s pop-punk" or "slow R&B ballad".'),
      structure: external_exports.string().optional().describe('Optional structure guidance, e.g. "verse, chorus, verse, chorus, bridge, chorus".')
    }
  },
  async ({ theme, style, structure }) => toToolResult(() => generateLyrics({ theme, style, structure }))
);
server.registerTool(
  "generate_song_suno",
  {
    title: "Generate a full song via Suno",
    description: "Generate a full song (music + optionally vocals) from a text prompt via the Suno API, optionally supplying your own lyrics or requesting an instrumental-only render. Requires SUNO_API_KEY in the environment/.env. NOTE: the Suno API integration shape is not yet verified against Suno's official current API \u2014 treat results/errors accordingly.",
    inputSchema: {
      prompt: external_exports.string().min(1).describe("Description of the song to generate, e.g. mood, genre, instrumentation."),
      lyrics: external_exports.string().optional().describe("Optional pre-written lyrics to sing (e.g. from generate_lyrics)."),
      instrumental: external_exports.boolean().optional().describe("If true, generate an instrumental (no vocals). Defaults to false.")
    }
  },
  async ({ prompt, lyrics, instrumental }) => toToolResult(() => generateSongSuno({ prompt, lyrics, instrumental }))
);
server.registerTool(
  "generate_image",
  {
    title: "Generate an image",
    description: "Generate an image from a text prompt using OpenAI's image API (model from OPENAI_IMAGE_MODEL, default gpt-image-2) and save it as a PNG under assets/generated/ in the repo. Returns the absolute file path of the saved image. Requires OPENAI_API_KEY in the environment/.env.",
    inputSchema: {
      prompt: external_exports.string().min(1).describe("Description of the image to generate."),
      size: external_exports.string().optional().describe('Optional image size, e.g. "1024x1024" (provider-specific). Defaults to 1024x1024.')
    }
  },
  async ({ prompt, size }) => toToolResult(() => generateImage({ prompt, size }))
);

// src/index.ts
async function main() {
  const transport = new StdioServerTransport();
  await server.connect(transport);
  console.error("[daw-pro-mcp] connected via stdio");
}
main().catch((err) => {
  console.error("[daw-pro-mcp] fatal error:", err instanceof Error ? err.stack ?? err.message : err);
  process.exit(1);
});
